output.sparql:
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?empress ?predecessor ?relation WHERE {
  ?empress wdt:P31 wd:Q5 ; wdt:P21 wd:Q6581072 .
  ?empress p:P39 ?position .
  ?position ps:P39 wd:Q208233 ; pq:P155 ?predecessor .
  {
    ?empress wdt:P22 ?predecessor .
    BIND("father" AS ?relation)
  } UNION {
    ?empress wdt:P25 ?predecessor .
    BIND("mother" AS ?relation)
  } UNION {
    ?empress wdt:P3373 ?predecessor .
    BIND("sibling" AS ?relation)
  }
}

args.sparql:
SELECT ?empress ?predecessor ?relation WHERE {
  ?empress wdt:P31 wd:Q5;          # Instance of human
           wdt:P21 wd:Q6581072.     # Female
  ?empress p:P39 ?position.
  ?position ps:P39 wd:Q208233;      # Position held: Emperor of Japan
            pq:P156 ?predecessor.    # Predecessor qualifier
  {
    ?empress wdt:P22 ?predecessor.  # Father
    BIND("father" AS ?relation)
  }
  UNION
  {
    ?empress wdt:P25 ?predecessor.  # Mother
    BIND("mother" AS ?relation)
  }
  UNION
  {
    ?empress wdt:P3373 ?predecessor. # Sibling
    BIND("sibling" AS ?relation)
  }
}

